const ctx = $input.first().json;
if (!ctx.results?.opportunities) throw new Error('Missing opportunities from Phase 4');

// Fan out opportunities for parallel quality checks
return ctx.results.opportunities.map(job => ({
  json: { job, ctx }
}));

const job = $('Advanced Dedup').item.json;
const httpRes = $input.first().json;

job.quality_report = job.quality_report || {};

if (httpRes.error) {
  // If timeout or 403 (Cloudflare block), mark UNVERIFIED instead of BROKEN to be safe
  if (httpRes.error.code === 'ECONNABORTED' || httpRes.error.status === 403) {
    job.quality_report.link_status = 'UNVERIFIED';
  } else {
    job.quality_report.link_status = 'BROKEN';
  }
} else {
  job.quality_report.link_status = 'VALID';
}

return [{ json: { job } }];

const job = $input.first().json;
const qr = job.quality_report || {};

// Base classification on strict rules
let classification = 'PENDING';

if (job.is_duplicate) {
  classification = 'REJECT';
  qr.reject_reason = 'Duplicate';
} else if (qr.link_status === 'BROKEN') {
  classification = 'REJECT';
  qr.reject_reason = 'Broken Apply Link';
} else if (qr.scam_risk > 60) {
  classification = 'REJECT';
  qr.reject_reason = 'High Scam Risk';
} else if (qr.ghost_probability > 75) {
  classification = 'LOW_PRIORITY';
  qr.reject_reason = 'Likely Ghost Job';
} else {
  // It's clean. Classify by match score from Phase 4
  const match = job.match_score || 0;
  if (match >= 85) classification = 'APPLY_IMMEDIATELY';
  else if (match >= 70) classification = 'HIGH_PRIORITY';
  else if (match >= 50) classification = 'GOOD_MATCH';
  else classification = 'LOW_PRIORITY';
}

qr.classification = classification;
job.quality_report = qr;

return [{ json: job }];

const allItems = $input.all();
const ctx = $('Fan Out Jobs').first().json.ctx;

const validJobs = [];
let rejectedCount = 0;

allItems.forEach(item => {
  const job = item.json;
  if (job.quality_report.classification === 'REJECT' || job.quality_report.classification === 'LOW_PRIORITY') {
    rejectedCount++;
  } else {
    validJobs.push(job);
  }
});

// Rebuild Context
const newCtx = { ...ctx };
newCtx.results.opportunities = validJobs; // Only keep the clean ones for ATS
newCtx.metadata = newCtx.metadata || {};
newCtx.metadata.quality_filtered = rejectedCount;
newCtx.agents_completed = [...(newCtx.agents_completed || []), 'job_quality'];

return [{ json: newCtx }];
